import{_ as e,c as r,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"用戶協議: 服務規則 | OpenCodeDocs","description":"了解 OpenCodeDocs 用戶協議的服務使用規則、智慧財產權歸屬和免責條款，明確雙方權利義務。","frontmatter":{"title":"用戶協議: 服務規則 | OpenCodeDocs","sidebarTitle":"5 分鐘了解規則","subtitle":"用戶協議: 服務規則","description":"了解 OpenCodeDocs 用戶協議的服務使用規則、智慧財產權歸屬和免責條款，明確雙方權利義務。"},"headers":[],"relativePath":"zh-tw/terms.md","filePath":"zh-tw/terms.md"}'),i={name:"zh-tw/terms.md"};function o(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="用戶服務協議" tabindex="-1">用戶服務協議 <a class="header-anchor" href="#用戶服務協議" aria-label="Permalink to &quot;用戶服務協議&quot;">​</a></h1><p>最後更新日期：2026-01-01 生效日期：2026-01-01</p><p>歡迎使用 OpenCodeDocs！在使用我們的服務之前，請仔細閱�本用戶服務協議（以下簡稱「本協議」）。使用我們的服務即表示您同意接受本協議的約束。</p><h2 id="_1-服務說明" tabindex="-1">1. 服務說明 <a class="header-anchor" href="#_1-服務說明" aria-label="Permalink to &quot;1. 服務說明&quot;">​</a></h2><p>OpenCodeDocs 是一個專注於 AI 工具教學的開放平台，提供以下服務：</p><ul><li><strong>教學內容</strong>：開源 AI 工具（如 Claude Code、Cursor、LangChain 等）的使用教學</li><li><strong>程式碼驗證</strong>：基於原始碼倉庫自動驗證教學中的程式碼可執行性</li><li><strong>社群功能</strong>：使用者可透過 GitHub 參與內容貢獻和討論</li></ul><p>我們保留隨時修改、暫停或終止部分或全部服務的權利，恕不另行通知。</p><h2 id="_2-帳號註冊與管理" tabindex="-1">2. 帳號註冊與管理 <a class="header-anchor" href="#_2-帳號註冊與管理" aria-label="Permalink to &quot;2. 帳號註冊與管理&quot;">​</a></h2><h3 id="註冊條件" tabindex="-1">註冊條件 <a class="header-anchor" href="#註冊條件" aria-label="Permalink to &quot;註冊條件&quot;">​</a></h3><ul><li>您必須年滿 16 歲（或在您所在地區達到法定年齡）</li><li>提供真實、準確的註冊資訊</li><li>每位使用者僅可註冊一個帳號</li></ul><h3 id="帳號安全" tabindex="-1">帳號安全 <a class="header-anchor" href="#帳號安全" aria-label="Permalink to &quot;帳號安全&quot;">​</a></h3><ul><li>您有責任保管好帳號憑證，不得與他人共享</li><li>如發現帳號被盜用，請立即聯繫我們</li><li>因帳號管理不善導致的損失，由您自行承擔</li></ul><h3 id="帳號註銷" tabindex="-1">帳號註銷 <a class="header-anchor" href="#帳號註銷" aria-label="Permalink to &quot;帳號註銷&quot;">​</a></h3><p>您可以隨時申請註銷帳號。註銷後，您的個人資料將在 30 天內刪除，但公開發佈的內容可能仍會保留。</p><h2 id="_3-使用者行為規範" tabindex="-1">3. 使用者行為規範 <a class="header-anchor" href="#_3-使用者行為規範" aria-label="Permalink to &quot;3. 使用者行為規範&quot;">​</a></h2><p>在使用本平台時，您同意不從事以下行為：</p><ul><li>發佈違法、有害、威脅、騷擾、誹謗或侵權的內容</li><li>冒充他人或虛假陳述身份</li><li>未經授權存取他人帳號或系統</li><li>干擾或破壞服務的正常執行</li><li>使用自動化工具大規模擷取內容（合理的 API 使用除外）</li><li>將教學內容用於商業目的而不遵守授權協議</li></ul><h2 id="_4-智慧財產權" tabindex="-1">4. 智慧財產權 <a class="header-anchor" href="#_4-智慧財產權" aria-label="Permalink to &quot;4. 智慧財產權&quot;">​</a></h2><h3 id="開源授權說明" tabindex="-1">開源授權說明 <a class="header-anchor" href="#開源授權說明" aria-label="Permalink to &quot;開源授權說明&quot;">​</a></h3><ul><li><strong>教學內容</strong>：採用 <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a> 協議，允許非商業性分享和改編，但需署名並以相同方式共享</li><li><strong>網站建置</strong>：本專案基於 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> 建置，遵循 MIT 協議</li><li><strong>使用者貢獻</strong>：您提交的內容預設授權平台在遵守上述協議的前提下使用</li></ul><p>OpenCodeDocs 的商標、Logo 和其他品牌標識受法律保護，未經授權不得使用。</p><h2 id="_5-免責聲明" tabindex="-1">5. 免責聲明 <a class="header-anchor" href="#_5-免責聲明" aria-label="Permalink to &quot;5. 免責聲明&quot;">​</a></h2><ul><li><strong>服務中斷</strong>：我們不保證服務不間斷或無錯誤。因維護、升級或不可抗力導致的服務中斷，我們不承擔責任</li><li><strong>內容準確性</strong>：教學內容僅供參考，我們不保證其在所有環境下的可用性</li><li><strong>程式碼使用風險</strong>：您執行教學中的程式碼需自行承擔風險，建議在隔離環境中測試</li><li><strong>第三方連結</strong>：本站可能包含指向第三方網站的連結，我們不對其內容負責</li></ul><h2 id="_6-協議修改" tabindex="-1">6. 協議修改 <a class="header-anchor" href="#_6-協議修改" aria-label="Permalink to &quot;6. 協議修改&quot;">​</a></h2><p>我們可能會不時修改本協議。修改後的協議將在網站上公佈，並透過以下方式通知您：</p><ul><li>在網站顯著位置公告</li><li>透過註冊信箱發送通知（如適用）</li></ul><p>繼續使用我們的服務即表示您接受修改後的協議。如您不同意修改，請停止使用服務。</p><h2 id="_7-爭議解決" tabindex="-1">7. 爭議解決 <a class="header-anchor" href="#_7-爭議解決" aria-label="Permalink to &quot;7. 爭議解決&quot;">​</a></h2><ul><li><strong>適用法律</strong>：本協議受中華人民共和國法律管轄</li><li><strong>爭議解決</strong>：雙方應友好協商解決爭議；協商不成的，任何一方可向被告所在地有管轄權的人民法院提起訴訟</li></ul><h2 id="_8-聯繫方式" tabindex="-1">8. 聯繫方式 <a class="header-anchor" href="#_8-聯繫方式" aria-label="Permalink to &quot;8. 聯繫方式&quot;">​</a></h2><p>如您對本協議有任何疑問，請聯繫：</p><ul><li><strong>信箱</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=e(i,[["render",o]]);export{p as __pageData,g as default};
